const VADPRS_PERF_ZH = ["优秀 (1)", "高于平均 (2)", "平均 (3)", "有些问题 (4)", "有严重问题 (5)"];
const VADPRS_PERF_KO = ["우수 (1)", "평균 이상 (2)", "평균 (3)", "다소 문제 있음 (4)", "문제 있음 (5)"];

